sql:
SELECT value
FROM economic_data_points
WHERE region_id = 0 AND date = '2022-01-01';

SELECT data_point_value_id, data_point_id, value, unit
FROM data_point_values
WHERE value > 2.0;

SELECT AVG(value) AS average_economic_value
FROM economic_data_points
WHERE region_id = 0 AND date >= '2022-01-01';

SELECT AVG(value) AS average_value
FROM data_point_values
WHERE unit = 'm/s';

external_knowledge:
- An indicator is a measurable value or characteristic that describes a particular aspect or dimension of a phenomenon or system; 
- Data points represent individual measurements of the indicators; 
- Average data point values provide a general idea of the central tendency of the measurements for each indicator.

sql:
SELECT economic_indicator_id, COUNT(economic_data_point_id) AS total_data_points
FROM economic_data_points
GROUP BY economic_indicator_id;
